import math

class Solution(object):
    def minArraySum(self, nums, k, op1, op2):
        n = len(nums)
        # dp[i][j] = min sum using i op1's and j op2's for first elements processed
        INF = float('inf')
        # State: (op1_remaining, op2_remaining) -> min sum
        dp = [[INF] * (op2 + 1) for _ in range(op1 + 1)]
        dp[op1][op2] = 0

        for v in nums:
            new_dp = [[INF] * (op2 + 1) for _ in range(op1 + 1)]
            for r1 in range(op1 + 1):
                for r2 in range(op2 + 1):
                    if dp[r1][r2] == INF:
                        continue
                    base = dp[r1][r2]
                    # Option 1: no operation
                    new_dp[r1][r2] = min(new_dp[r1][r2], base + v)
                    # Option 2: op1 only (ceil(v/2))
                    if r1 > 0:
                        new_dp[r1-1][r2] = min(new_dp[r1-1][r2], base + math.ceil(v / 2))
                    # Option 3: op2 only (v - k, if v >= k)
                    if r2 > 0 and v >= k:
                        new_dp[r1][r2-1] = min(new_dp[r1][r2-1], base + v - k)
                    # Option 4: op1 then op2
                    if r1 > 0 and r2 > 0:
                        v1 = math.ceil(v / 2)
                        if v1 >= k:
                            new_dp[r1-1][r2-1] = min(new_dp[r1-1][r2-1], base + v1 - k)
                    # Option 5: op2 then op1
                    if r1 > 0 and r2 > 0 and v >= k:
                        v2 = v - k
                        new_dp[r1-1][r2-1] = min(new_dp[r1-1][r2-1], base + math.ceil(v2 / 2))
            dp = new_dp

        return min(dp[r1][r2] for r1 in range(op1+1) for r2 in range(op2+1) if dp[r1][r2] < INF)
